@namespace CheckoutWizard

<fieldset>
    <legend>Payment Information</legend>

    <div class="form-field">
        <label for="cardNumber">Card Number</label>
        <input id="cardNumber" @bind="Payment.CardNumber" @bind:event="oninput" />
    </div>

    <div class="form-field">
        <label for="expiry">Expiry Date</label>
        <input id="expiry" placeholder="MM/YY" @bind="Payment.ExpiryDate" @bind:event="oninput" />
    </div>
</fieldset>

@if (!string.IsNullOrEmpty(_error))
{
    <div class="validation-error" role="alert">@_error</div>
}

<div class="button-group">
    <button @onclick="OnBack">Back</button>
    <button class="primary" @onclick="Submit">Place Order</button>
</div>

@code {
    [Parameter, EditorRequired] public PaymentInfo Payment { get; set; } = default!;
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnPlaceOrder { get; set; }

    private string? _error;

    private async Task Submit()
    {
        if (string.IsNullOrWhiteSpace(Payment.CardNumber) ||
            string.IsNullOrWhiteSpace(Payment.ExpiryDate))
        {
            _error = "Card number and expiry date are required.";
            return;
        }

        _error = null;
        await OnPlaceOrder.InvokeAsync();
    }
}

